std::vector<std::vector<double>> transpose(const std::vector<std::vector<double>>& m){
    int rows = (int)m.size();
    int cols = (int)m[0].size();
    std::vector<std::vector<double>> t(cols, std::vector<double>(rows, 0.0));
    for (int i = 0; i < rows; ++i)
        for (int j = 0; j < cols; ++j)
            t[j][i] = m[i][j];
    return t;
}

